def buckets = ctx.payload.aggregations.by_index.buckets;
def approved = [];
for (def b : buckets) {
  def latest = b.latest_state.hits.hits[0]._source;
  if (!'approved_gate2'.equals(latest.state)) continue;
  String requestId = latest.index_name + '-scheduled-' + ctx.execution_time.toString();
  approved.add([
    '@timestamp': ctx.execution_time,
    'request_id': requestId,
    'index_name': latest.index_name,
    'state': 'scheduled_for_deletion',
    'updated_at': ctx.execution_time,
    'phase_age_days': latest.phase_age_days != null ? latest.phase_age_days : 0,
    'gate1_approved_by': latest.gate1_approved_by != null ? latest.gate1_approved_by : 'unknown',
    'gate2_approved_by': latest.gate2_approved_by != null ? latest.gate2_approved_by : 'unknown',
    'gate2_approved_at': latest.gate2_approved_at != null ? latest.gate2_approved_at : ctx.execution_time,
    'delete_policy_applied': true,
    'watcher_id': ctx.metadata.watcher_id
  ]);
}
return ['approved': approved, 'approved_count': approved.size()];
